/* Placeholder qrcode vendor file.
   If you want a full QR generator, run the vendorize script to fetch a real build.
   This stub provides a minimal API `QRCode.toCanvas(canvas, text)` that fills the
   canvas with the text when a full library is not available.
*/
(function(global){
  function toCanvas(canvas, text){
    try{
      var ctx = canvas.getContext('2d');
      ctx.fillStyle = '#fff'; ctx.fillRect(0,0,canvas.width,canvas.height);
      ctx.fillStyle = '#111'; ctx.font = Math.max(12, Math.round(canvas.width/20))+'px sans-serif';
      ctx.textAlign = 'center'; ctx.textBaseline='middle';
      ctx.fillText(text, canvas.width/2, canvas.height/2);
      return Promise.resolve();
    }catch(e){ return Promise.reject(e); }
  }
  global.QRCode = { toCanvas };
})(window);
